/** No-op cache adapter that never stores or returns any data. Used to disable caching. */
export class NullCacheAdapter {
    /**
     * @inheritDoc
     */
    get(name) {
        return null;
    }
    /**
     * @inheritDoc
     */
    set(name, data, origin) {
        // ignore
    }
    /**
     * @inheritDoc
     */
    remove(name) {
        // ignore
    }
    /**
     * @inheritDoc
     */
    clear() {
        // ignore
    }
}
